package main

import (
	"fmt"
	"os"
	"path/filepath"
	"strings"

	"github.com/openshift/openshift-tests-private/test/extended/csi"

	"k8s.io/kubernetes/test/e2e/framework/testfiles"
	"k8s.io/kubernetes/test/e2e/storage/external"
)

// Constants for environment variables used to control the CSI driver installation and testing.
const (
	manifestEnvVar       = "TEST_CSI_DRIVER_FILES"  // Environment variable to store the list of CSI driver manifests.
	installDriversEnvVar = "TEST_INSTALL_CSI_DRIVERS" // Environment variable to control the installation of CSI drivers.
)

// Global variable to store a debug message for testing purposes.
var globalVar string = "Nir Debug"

// Function to initialize the OpenShift CSI suite by defining CSI tests from the TEST_CSI_DRIVER_FILES environment variable.
// This function is responsible for installing CSI drivers and loading their manifests for testing.
func initCSITests(dryRun bool) error {
	// Print the global debug message for testing purposes.
	fmt.Print(globalVar)

	// Get the list of CSI drivers to install from the TEST_INSTALL_CSI_DRIVERS environment variable.
	driverList := os.Getenv(installDriversEnvVar)
	if driverList != "" {
		// Split the driver list into individual drivers.
		drivers := strings.Split(driverList, ",")

		// Iterate through each driver and install it using the InstallCSIDriver function.
		for _, driver := range drivers {
			manifestFile, err := csi.InstallCSIDriver(driver, dryRun)
			if err != nil {
				// Return an error if the driver installation fails.
				return fmt.Errorf("failed to install CSI driver from %q: %s", driver, err)
			}

			// Store the newly installed manifest in the TEST_CSI_DRIVER_FILES environment variable.
			// This allows child processes to access the manifest.
			manifestList := os.Getenv(manifestEnvVar)
			if len(manifestList) > 0 {
				manifestList += ","
			}
			manifestList += manifestFile
			os.Setenv(manifestEnvVar, manifestList)
		}
	}

	// Clear the TEST_INSTALL_CSI_DRIVERS environment variable to prevent child processes from installing the drivers.
	os.Setenv(installDriversEnvVar, "")

	// Get the list of manifests from the TEST_CSI_DRIVER_FILES environment variable.
	manifestList := os.Getenv(manifestEnvVar)
	if manifestList != "" {
		// Split the manifest list into individual manifests.
		manifests := strings.Split(manifestList, ",")

		// Iterate through each manifest and load it using the AddDriverDefinition function.
		for _, manifest := range manifests {
			if err := external.AddDriverDefinition(manifest); err != nil {
				// Return an error if the manifest loading fails.
				return fmt.Errorf("failed to load manifest from %q: %s", manifest, err)
			}

			// Register the base directory of the manifest file as a file source.
			// This allows the CSI driver's storage class to be referenced in the manifest file.
			testfiles.AddFileSource(testfiles.RootFileSource{
				Root: filepath.Dir(manifest),
			})
		}
	}

	return nil
}

// Function to install a CSI driver using the InstallCSIDriver function from the csi package.
// This function is responsible for installing a single CSI driver.
func installCSI_driver(driver string, dryRun bool) (string, error) {
	// Call the InstallCSIDriver function from the csi package to install the CSI driver.
	manifestFile, err := csi.InstallCSIDriver(driver, dryRun)
	if err != nil {
		// Return an error if the driver installation fails.
		return "", fmt.Errorf("failed to install CSI driver from %q: %s", driver, err)
	}

	return manifestFile, nil
}

// Function to load a CSI driver manifest using the AddDriverDefinition function from the external package.
// This function is responsible for loading a single CSI driver manifest.
func loadCSI_driver_manifest(manifest string) error {
	// Call the AddDriverDefinition function from the external package to load the CSI driver manifest.
	if err := external.AddDriverDefinition(manifest); err != nil {
		// Return an error if the manifest loading fails.
		return fmt.Errorf("failed to load manifest from %q: %s", manifest, err)
	}

	return nil
}
```

The `initCSITests` function is the main entry point for the CSI testing suite. It initializes the OpenShift CSI suite by defining CSI tests from the `TEST_CSI_DRIVER_FILES` environment variable. This function is responsible for installing CSI drivers and loading their manifests for testing.

The `installCSI_driver` function is a helper function that installs a single CSI driver using the `InstallCSIDriver` function from the `csi` package. This function is responsible for installing a single CSI driver.

The `loadCSI_driver_manifest` function is another helper function that loads a CSI driver manifest using the `AddDriverDefinition` function from the `external` package. This function is responsible for loading a single CSI driver manifest.

These functions work together to support modularity by breaking down the complex task of installing and loading CSI drivers into smaller, more manageable functions. This makes it easier to test and maintain the OpenShift QE project.

